import React from "react";

export default function LightStreak({ delay }) {
  return (
    <div 
      style={{
        position: "absolute",
        top: `${Math.random() * 50 + 10}%`,
        left: "-15%",
        width: "250px",
        height: "2px",
        background: "linear-gradient(90deg, transparent 0%, var(--primary) 50%, var(--secondary) 80%, transparent 100%)",
        animation: `shoot 4s cubic-bezier(0.25, 1, 0.5, 1) ${delay}s infinite`,
        opacity: 0.25, 
        pointerEvents: "none",
        zIndex: 1
      }} 
    />
  );
}
